2	/**
3	 * ReviewLens AI — automated demo recorder
4	 *
5	 * Records a full walkthrough of all features:
6	 *   1. Home page
7	 *   2. Ingestion (URL → session)
8	 *   3. Proactive Insight Brief
9	 *   4. Quick-Start Prompts
10	 *   5. AI response + Citations
11	 *   6. Contextual Follow-Up Chips
12	 *   7. Guardrails — off-topic refusal
13	 *   8. Guardrails — input validation
14	 *
15	 * Usage:
16	 *   node scripts/record-demo.js
17	 *
18	 * Env vars (all optional):
19	 *   BASE_URL            — default: https://reviewlens-ai-f6lj.onrender.com
20	 *   TRUSTPILOT_URL      — default: https://www.trustpilot.com/review/notion.so
21	 *   REVIEW_CAP          — default: 10  (keep small for demo speed)
22	 *   EXISTING_SESSION_ID — skip ingestion, jump straight to this session
23	 *   CHROME_PATH         — override Chrome executable path
24	 *   SKIP_VOICEOVER      — set to "1" to skip TTS generation
25	 *
26	 * Output: demo-out/demo.mp4  (video + voice-over mixed)
27	 *
28	 * Target duration: ~3 minutes
29	 */
30	
31	const { chromium } = require('playwright-core');
32	const { execSync, spawnSync, execFileSync } = require('child_process');
33	const path = require('path');
34	const fs = require('fs');
35	
36	const BASE_URL = process.env.BASE_URL || 'https://reviewlens-ai-f6lj.onrender.com';
37	const TRUSTPILOT_URL = process.env.TRUSTPILOT_URL || 'https://www.trustpilot.com/review/notion.so';
38	const REVIEW_CAP = process.env.REVIEW_CAP || '10';
39	const EXISTING_SESSION_ID = process.env.EXISTING_SESSION_ID || '';
40	const CHROME_PATH =
41	  process.env.CHROME_PATH ||
42	  '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome';
43	const SKIP_VOICEOVER = process.env.SKIP_VOICEOVER === '1';
44	
45	const OUT_DIR = path.join(__dirname, '..', 'demo-out');
46	const WEBM_PATH = path.join(OUT_DIR, 'demo.webm');
47	const VIDEO_ONLY_MP4 = path.join(OUT_DIR, 'demo-video-only.mp4');
48	const NARRATION_PATH = path.join(OUT_DIR, 'narration.aiff');
49	const MP4_PATH = path.join(OUT_DIR, 'demo.mp4');
50	
51	const pause = (ms) => new Promise((r) => setTimeout(r, ms));
52	
53	async function slowType(locator, text, delayMs = 50) {
54	  await locator.click();
55	  for (const ch of text) {
56	    await locator.type(ch);
57	    await pause(delayMs);
58	  }
59	}
60	
61	async function waitForInsightBrief(page) {
62	  await page.waitForSelector('text=AI Insights', { timeout: 60_000 });
63	  try {
64	    await page.waitForSelector('text=Analyzing reviews…', { state: 'detached', timeout: 90_000 });
65	  } catch { /* already gone or never appeared */ }
66	}
67	
68	async function waitForAssistantResponse(page) {
69	  try {
70	    await page.waitForSelector('text=Thinking…', { timeout: 10_000 });
71	  } catch { /* already gone */ }
72	  await page.waitForSelector('text=Thinking…', { state: 'detached', timeout: 90_000 });
73	}
74	
75	async function waitForFollowUpChips(page) {
76	  try {
77	    await page.waitForSelector('.animate-pulse', { state: 'detached', timeout: 30_000 });
78	  } catch { /* ignore */ }
79	  await pause(800);
80	}
81	
82	// ─────────────────────────────────────────────────────────
83	// Voice-over: macOS `say` TTS
84	// Each scene has a narration line. We generate one audio
85	// segment per scene with silence padding, then stitch with
86	// ffmpeg into a single AIFF, then mix over the video.
87	// ─────────────────────────────────────────────────────────
88	
89	const NARRATION_VOICE = 'Samantha';
90	const NARRATION_RATE = 160; // words per minute
91	
92	const SCENES = [
93	  // [scene_id, duration_ms, narration_text]
94	  ['home',       8_000,  'Welcome to ReviewLens AI — the fastest way to turn customer reviews into product insights.'],
95	  ['ingest',    12_000,  'Simply paste a Trustpilot URL and set a review cap. ReviewLens scrapes and stores the data automatically.'],
96	  ['progress',  10_000,  'Ingestion runs in real time. Watch as pages are fetched and reviews are saved to the database.'],
97	  ['session',    6_000,  'Once ingestion completes, you land on your session dashboard.'],
98	  ['insights',  18_000,  'ReviewLens immediately generates a proactive Insight Brief — key themes, sentiment patterns, and actionable signals — without you asking a single question.'],
99	  ['expand',    12_000,  'Click the card to expand the full brief. Each theme is grounded in the actual review data.'],
100	  ['quickstart', 8_000,  'Quick-Start Prompts let you jump straight to the most valuable questions with a single click.'],
101	  ['response',  20_000,  'Claude analyzes every review in context and streams a structured answer back to you, with citations linking each claim to its source review.'],
102	  ['citations', 10_000,  'Every factual claim includes an inline citation. Expand sources to see the exact reviews that back each statement.'],
103	  ['chips',     15_000,  'After each answer, contextual Follow-Up Chips suggest the next most relevant questions — so the analysis drives itself.'],
104	  ['chip_resp', 18_000,  'Click a chip to drill deeper. The conversation builds on prior context, giving you richer answers with every exchange.'],
105	  ['guardrail_refusal', 16_000, 'ReviewLens includes built-in guardrails. Ask about anything outside the review data — like a competitor or a general knowledge question — and the model politely refuses.'],
106	  ['guardrail_input',   10_000, 'Short or empty inputs are caught client-side before they ever reach the model.'],
107	  ['final',     7_000,   'ReviewLens AI — ship smarter products by listening to every customer, at scale.'],
108	];
109	
110	function generateNarrationAudio(scenes) {
111	  if (SKIP_VOICEOVER) {
112	    console.log('⏭   SKIP_VOICEOVER=1 — skipping TTS generation.');
113	    return null;
114	  }
115	
116	  console.log('\n🎙  Generating voice-over narration…');
117	
118	  const segmentFiles = [];
119	  const silencePath = path.join(OUT_DIR, 'silence_500ms.aiff');
120	
121	  // Generate 500ms silence clip once
122	  spawnSync('ffmpeg', [
123	    '-y', '-f', 'lavfi', '-i', 'anullsrc=r=44100:cl=mono',
124	    '-t', '0.5', '-c:a', 'pcm_s16le', silencePath,
125	  ], { stdio: 'inherit' });
126	
127	  for (const [id, _durationMs, text] of scenes) {
128	    const segPath = path.join(OUT_DIR, `narr_${id}.aiff`);
129	    console.log(`    TTS: ${id}`);
130	    const result = spawnSync('say', [
131	      '-v', NARRATION_VOICE,
132	      '-r', String(NARRATION_RATE),
133	      '-o', segPath,
134	      '--data-format=LEF32@44100',
135	      text,
136	    ], { stdio: 'inherit' });
137	    if (result.status !== 0) {
138	      console.warn(`    Warning: say failed for scene ${id}`);
139	    }
140	    segmentFiles.push(segPath);
141	    segmentFiles.push(silencePath); // short gap between scenes
142	  }
143	
144	  // Concatenate all segments into one AIFF using ffmpeg concat
145	  // Build a concat input list
146	  const concatListPath = path.join(OUT_DIR, 'narr_concat.txt');
147	  const listContent = segmentFiles
148	    .filter(f => fs.existsSync(f))
149	    .map(f => `file '${f}'`)
150	    .join('\n');
151	  fs.writeFileSync(concatListPath, listContent);
152	
153	  console.log('    Concatenating narration segments…');
154	  const concatResult = spawnSync('ffmpeg', [
155	    '-y', '-f', 'concat', '-safe', '0',
156	    '-i', concatListPath,
157	    '-c', 'copy',
158	    NARRATION_PATH,
159	  ], { stdio: 'inherit' });
160	
161	  if (concatResult.status !== 0) {
162	    console.warn('    Warning: narration concat failed — demo will have no audio.');
163	    return null;
164	  }
165	
166	  // Cleanup segment files
167	  for (const f of segmentFiles) {
168	    if (f !== silencePath && fs.existsSync(f)) fs.unlinkSync(f);
169	  }
170	  if (fs.existsSync(silencePath)) fs.unlinkSync(silencePath);
171	  if (fs.existsSync(concatListPath)) fs.unlinkSync(concatListPath);
172	
173	  console.log(`    Narration saved: ${NARRATION_PATH}`);
174	  return NARRATION_PATH;
175	}
